--- src/refresh-queue.mjs	
+++ src/refresh-queue.mjs	
@@ -1,15 +1,18 @@
-let inflight;
+const inflightByTenant = new Map();

 export function enqueueRefresh(tenantID, refresh) {
+  const inflight = inflightByTenant.get(tenantID);
   if (inflight) return inflight;
-  inflight = Promise.resolve()
+
+  const next = Promise.resolve()
     .then(() => refresh(tenantID))
     .finally(() => {
-      inflight = undefined;
+      inflightByTenant.delete(tenantID);
     });
-  return inflight;
+  inflightByTenant.set(tenantID, next);
+  return next;
 }

 export function resetQueueForTests() {
-  inflight = undefined;
+  inflightByTenant.clear();
 }

Index: test/refresh-queue.test.mjs
===================================================================
--- test/refresh-queue.test.mjs	
+++ test/refresh-queue.test.mjs	
@@ -1,16 +1,32 @@
 import test from "node:test";
 import assert from "node:assert/strict";
 import { enqueueRefresh, resetQueueForTests } from "../src/refresh-queue.mjs";

 test("same tenant refresh calls coalesce", async () => {
   resetQueueForTests();
   let calls = 0;
   const refresh = async () => {
     calls += 1;
     await new Promise((resolve) => setTimeout(resolve, 5));
     return `token-${calls}`;
   };
   const [a, b] = await Promise.all([enqueueRefresh("tenant-a", refresh), enqueueRefresh("tenant-a", refresh)]);
   assert.equal(calls, 1);
   assert.equal(a, b);
 });
+
+test("different tenants refresh independently", async () => {
+  resetQueueForTests();
+  const refreshedTenants = [];
+  const refresh = async (tenantID) => {
+    refreshedTenants.push(tenantID);
+    await new Promise((resolve) => setTimeout(resolve, 5));
+    return `token-${tenantID}`;
+  };
+
+  const [a, b] = await Promise.all([enqueueRefresh("tenant-a", refresh), enqueueRefresh("tenant-b", refresh)]);
+
+  assert.deepEqual(refreshedTenants.sort(), ["tenant-a", "tenant-b"]);
+  assert.equal(a, "token-tenant-a");
+  assert.equal(b, "token-tenant-b");
+});

